// phrocs is a PostHog-branded dev process runner built with Bubble Tea.
//
// It is a drop-in replacement for mprocs: it reads the same YAML config
// that `hogli dev:generate` produces and renders a customisable TUI with a
// per-process sidebar, scrollable output panes, and hogli-aware keybindings.
//
// Usage:
//
//	phrocs [--debug] --config <config.yaml>
//
// Flags:
//
//	--config Path to the YAML config file generated by `hogli dev:generate`.
//	--debug  Write a debug log to /tmp/phrocs-debug.log (key inputs, proc
//	         selection changes, status transitions, etc.)
package main

import (
	"fmt"
	"log"
	"os"

	tea "charm.land/bubbletea/v2"
	"github.com/posthog/posthog/phrocs/internal/config"
	"github.com/posthog/posthog/phrocs/internal/docker"
	"github.com/posthog/posthog/phrocs/internal/expand"
	"github.com/posthog/posthog/phrocs/internal/process"
	"github.com/posthog/posthog/phrocs/internal/tui"
)

func main() {
	var configPath string
	var logger *log.Logger

	// Parse flags: --config <path>, --debug
	for i := 1; i < len(os.Args); i++ {
		switch os.Args[i] {
		case "--config":
			// Next arg is the config file path
			if i+1 < len(os.Args) {
				configPath = os.Args[i+1]
				i++
			}
		case "--debug":
			f, err := os.OpenFile("/tmp/phrocs-debug.log", os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
			if err != nil {
				fmt.Fprintf(os.Stderr, "phrocs: open debug log: %v\n", err)
				os.Exit(1)
			}
			logger = log.New(f, "", log.LstdFlags|log.Lmicroseconds)
			logger.Println("debug logging started")
		}
	}

	if configPath == "" {
		fmt.Fprintln(os.Stderr, "usage: phrocs [--debug] --config <config.yaml>")
		os.Exit(1)
	}

	cfg, err := config.Load(configPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "phrocs: load config: %v\n", err)
		os.Exit(1)
	}

	// Build sidebar expanders. Currently just docker compose, but the
	// interface is generic so other providers can be added later.
	var expanders []expand.Expander

	// Detect compose processes, strip their log-follow tails (phrocs takes
	// over per-container log streaming), and register the compose expander.
	shells := make(map[string]string, len(cfg.Procs))
	for name, proc := range cfg.Procs {
		shells[name] = proc.Shell
	}
	composeExp := docker.NewComposeExpander(shells, cfg.Scrollback, logger)
	if composeExp.HasComposeProcs() {
		expanders = append(expanders, composeExp)
		// Strip `docker compose logs -f` from compose process shells so the
		// compose process only does `up -d`. Phrocs handles per-container
		// log streaming via the expander.
		for name, proc := range cfg.Procs {
			if composeExp.IsComposeProc(name) {
				proc.Shell = docker.StripComposeLogs(proc.Shell)
				cfg.Procs[name] = proc
			}
		}
	}

	mgr := process.NewManager(cfg)
	m := tui.New(mgr, expanders, cfg.MouseScrollSpeed, logger)
	p := tea.NewProgram(m)

	// Wire up the send function for async message passing
	mgr.SetSend(p.Send)
	composeExp.SetSend(p.Send)

	go mgr.StartAll()

	if _, err := p.Run(); err != nil {
		fmt.Fprintf(os.Stderr, "phrocs: %v\n", err)
		os.Exit(1)
	}
}
